Your task is to write a Jest test case that exposes a specific mutation in a JavaScript/TypeScript project.

MUTATION DETAILS
The mutation affects the following file:
sinks/drain.js
Here is the full content of that file (shown with a <PLACEHOLDER> marker):
'use strict'

module.exports = function drain (op, done) {
  var read, abort

  // Declared here so that it captures the drain's stack trace
  var doneLackingErr
  if (!done) {
    doneLackingErr = new Error('no done callback supplied')
  }

  function sink (_read) {
    read = _read
    if(abort) return sink.abort()
    //this function is much simpler to write if you
    //just use recursion, but by using a while loop
    //we do not blow the stack if the stream happens to be sync.
    ;(function next() {
        var loop = true, cbed = false
        while(loop) {
          cbed = false
          read(null, function (end, data) {
            cbed = true
            if(end = end || abort) {
              loop = false
              if(done) done(end === true ? null : end)
              else if(end && end !== true) {
                console.warn(doneLackingErr)
                throw end
              }
            }
            else if(op && false === op(data) || abort) {
              loop = false
              read(abort || true, done || function () {})
            }
            else if(!loop){
              next()
            }
          })
          if(!cbed) {
            loop = false
            return
          }
        }
      })()
  }

  sink.abort = function (err, cb) {
    if('function' == typeof err)
      <PLACEHOLDER>
    abort = err || true
    if(read) return read(abort, cb || function () {})
  }

  return sink
}

In the original code, <PLACEHOLDER> has the value:

-         cb = err, err = true
In the mutated code, <PLACEHOLDER> has the value:

+         cb = err, err = false


YOUR TASK
Write one Jest test file that:
    1. Passes when run against the original code.
    2. Fails when run against the mutated code.
    3. Tests the behavior of the mutated file in a way that reliably detects the mutation.
The test will be saved at the following path, relative to this test-generation project’s root:
llm-cache/anthropic_claude-sonnet-4.6/temp_0.5/withoutTests/cached/artifacts/pull-stream/attempt_1/pending_category/mutant-fe4b62b/testCase.test.ts

ALLOWED LIBRARIES
You may use:
    1. Any built-in Node.js modules (e.g., fs, path, crypto, etc.).

You may not use any other third-party libraries.

Looking at the mutation, the difference is:
- Original: `cb = err, err = true` (sets err to `true` when a function is passed)
- Mutated: `cb = err, err = false` (sets err to `false` when a function is passed)

This affects the `sink.abort()` method when called with a function as the first argument. In the original, `abort` gets set to `true` (truthy), but in the mutated version, `abort` gets set to `false` (falsy).

The key observable difference: when `abort` is `false`, the condition `if(abort) return sink.abort()` in `sink` won't trigger, and `read(abort, cb || function () {})` will call `read(false, ...)` instead of `read(true, ...)`.

I need to test that when `sink.abort(callback)` is called (with a function as the only argument), the stream properly aborts - meaning the `read` function receives a truthy abort signal.

```typescript
import drain from "../../../../../../../../../../../subject_repositories/pull-stream/sinks/drain.js";

describe("drain sink.abort with callback as first argument", () => {
  it("should pass truthy abort signal to read when abort is called with only a callback", (done) => {
    // Create a source that tracks what end values it receives
    const receivedEndValues: any[] = [];

    let readCallback: ((end: any, data?: any) => void) | null = null;

    // A source that captures the read callback so we can control it
    function source(end: any, cb: (end: any, data?: any) => void) {
      receivedEndValues.push(end);
      readCallback = cb;

      if (end) {
        // Stream is being aborted/ended
        cb(end);
        return;
      }

      // Don't call cb immediately - let the test control it
    }

    const sink = drain(null, null);
    sink(source);

    // At this point, source was called with (null, cb) - first read
    // readCallback is set, receivedEndValues = [null]

    // Now call abort with just a callback (no error)
    // In original: cb = callback, err = true -> abort = true -> read(true, callback)
    // In mutated: cb = callback, err = false -> abort = false -> read(false, callback)
    const abortCallback = jest.fn();
    sink.abort(abortCallback);

    // The source should have been called with the abort signal
    // In original: receivedEndValues should contain true (truthy abort)
    // In mutated: receivedEndValues should contain false (falsy - not a real abort)

    // Check that the abort signal passed to read is truthy
    const lastEndValue = receivedEndValues[receivedEndValues.length - 1];
    expect(lastEndValue).toBeTruthy();

    done();
  });
});
```

Wait, I need to reconsider. The `sink` function sets `abort` before calling `read`. Let me trace through more carefully and write a cleaner test.

```typescript
import drain from "../../../../../../../../../../../subject_repositories/pull-stream/sinks/drain.js";

describe("drain sink.abort with callback as first argument", () => {
  it("should use truthy abort value when abort is called with only a callback function", (done) => {
    const abortSignals: any[] = [];

    // Source that records all end/abort signals it receives
    function source(end: any, cb: (end: any, data?: any) => void) {
      abortSignals.push(end);
      if (end) {
        cb(end);
      }
      // If end is falsy, don't call cb (keep stream open)
    }

    const sink = drain(null, null);
    sink(source);

    // source was called with (null, cb) - initial read, abortSignals = [null]
    // Now abort with just a callback
    const abortCb = jest.fn();
    sink.abort(abortCb);

    // In original: abort = true, so read(true, abortCb) is called
    // In mutated: abort = false, so read(false, abortCb) is called
    const lastSignal = abortSignals[abortSignals.length - 1];

    // The abort signal should be truthy (true in original, false in mutated)
    expect(lastSignal).toBeTruthy();
    done();
  });
});
```

Let me trace through the code more carefully.

When `sink.abort(callback)` is called with a function:
- Original: `cb = callback, err = true` → `abort = true` → `read(true, callback)`
- Mutated: `cb = callback, err = false` → `abort = false` → `read(false, callback)`

The issue is that `read(false, callback)` passes `false` as the end signal. In the source, `false` is falsy, so the source might treat it as "not ended" and return data instead of terminating.

The key difference: with `abort = false`, the `if(abort) return sink.abort()` check in `sink` won't work, and `read(false, cb)` is called which a source might treat as a normal read request.

```typescript
import drain from "../../../../../../../../../../../subject_repositories/pull-stream/sinks/drain.js";

describe("drain sink.abort with callback as first argument", () => {
  it("should terminate the stream with a truthy end signal when abort is called with only a callback", (done) => {
    let callCount = 0;
    const endSignals: any[] = [];

    // Source that records the end signals it receives
    // When called with a falsy end signal, it returns data (stream continues)
    // When called with a truthy end signal, it terminates
    function source(end: any, cb: (end: any, data?: any) => void) {
      callCount++;
      endSignals.push(end);

      if (end) {
        // Truthy end: stream is being aborted/ended properly
        cb(end);
      } else {
        // Falsy end (null or false): source treats this as a data request
        // Return some data to keep stream going
        cb(null, 'data');
      }
    }

    // Use an op that never returns false, so stream keeps going
    const sink = drain((_data: any) => { /* keep going */ }, (err: any) => {
      // done callback - check what happened
      // In original: abort=true, so done(null) is called (true === true means null)
      // In mutated: abort=false, stream may not terminate properly
    });

    sink(source);

    // After sink(source), the while loop runs synchronously since source calls cb immediately
    // The stream will keep looping since op never returns false
    // But we need to abort it

    const abortCb = jest.fn();
    sink.abort(abortCb);

    // In original: abort=true -> read(true, abortCb) -> source gets end=true -> cb(true) -> abortCb called
    // In mutated: abort=false -> read(false, abortCb) -> source gets end=false -> cb(null, 'data') -> abortCb NOT called with end

    expect(abortCb).toHaveBeenCalled();
    done();
  });
});
```

Hmm, the synchronous loop makes this tricky. Let me write a cleaner version with an async source:

```typescript
import drain from "../../../../../../../../../../../subject_repositories/pull-stream/sinks/drain.js";

describe("drain sink.abort with callback as first argument", () => {
  it("should call the abort callback after aborting with truthy signal when only a callback is passed to abort", (done) => {
    let pendingCb: ((end: any, data?: any) => void) | null = null;

    // Async source - holds the callback until we decide to respond
    function source(end: any, cb: (end: any, data?: any) => void) {
      if (end) {
        cb(end);
        return;
      }
      // Store callback, don't call it yet (async source)
      pendingCb = cb;
    }

    const sink = drain(null, null);
    sink(source);

    // Now pendingCb is set (source is waiting to provide data)
    // Call abort with just a callback
    const abortCb = jest.fn();
    sink.abort(abortCb);

    // In original: abort=true -> read(true, abortCb) -> source gets end=true -> cb(true) -> abortCb(true)
    // In mutated: abort=false -> read(false, abortCb) -> source gets end=false -> pendingCb stored again, abortCb NOT called

    expect(abortCb).toHaveBeenCalled();
    done();
  });
});
```

The crash was caused by an infinite loop - when `abort=false` and the source returns data synchronously, the drain loop runs forever. I need to use an async source that holds the callback, so the synchronous loop exits before abort is called.

Let me carefully trace the behavior:

- With async source: `sink(source)` → source called with `(null, cb)` → source stores cb, doesn't call it → loop exits (`!cbed` is true) → returns
- Then `sink.abort(abortCb)` is called:
  - Original: `cb=abortCb, err=true` → `abort=true` → `read(true, abortCb)` → source gets `end=true` → calls `abortCb(true)`
  - Mutated: `cb=abortCb, err=false` → `abort=false` → `read(false, abortCb)` → source gets `end=false` → stores abortCb as pendingCb, never calls it as abort

```typescript
import drain from "../../../../../../../../../../../subject_repositories/pull-stream/sinks/drain.js";

describe("drain sink.abort", () => {
  it("should call the abort callback when abort is invoked with only a callback argument", (done) => {
    let storedReadCb: ((end: any, data?: any) => void) | null = null;
    const endSignalsReceived: any[] = [];

    // Async source: on first call (end=null), stores cb without calling it
    // On subsequent calls with truthy end, calls cb(end) immediately
    function source(end: any, cb: (end: any, data?: any) => void) {
      endSignalsReceived.push(end);
      if (end) {
        cb(end);
      } else {
        storedReadCb = cb;
      }
    }

    const sink = drain(null, null);
    sink(source);

    // source was called with (null, cb) - async, so loop exited
    expect(storedReadCb).not.toBeNull();

    const abortCb = jest.fn();
    sink.abort(abortCb);

    // Original: abort=true -> read(true, abortCb) -> source gets end=true -> abortCb(true) called
    // Mutated:  abort=false -> read(false, abortCb) -> source gets end=false -> abortCb NOT called

    expect(abortCb).toHaveBeenCalled();
    done();
  });
});
```

Let me trace through the mutated code more carefully.

In the mutated code: `cb = err, err = false` → `abort = false || true = true` (because `abort = err || true` and `err = false`, so `false || true = true`).

Wait! `abort = err || true` - even with `err = false`, `abort` becomes `true`! So the abort value is the same. The difference must be in what gets passed to `read`.

Looking again: `read(abort, cb || function () {})` - `abort` is `true` in both cases.

The real difference: in original `err = true`, in mutated `err = false`. But `abort = err || true` = `true` either way.

So what actually differs? The `err` variable itself... but it's not used after that assignment except as `abort = err || true`.

Wait, let me re-read: `abort = err || true` - yes, always `true`. So the abort signal to `read` is always `true`. The `abortCb` should be called in both cases...

That explains why my previous tests passed on both. The mutation might have a subtler effect - perhaps when `sink` is called after abort is set, or when `err` is something other than a function.

Let me think about what `err` being `false` vs `true` affects when passed as the abort error to `done`:

```typescript
import drain from "../../../../../../../../../../../subject_repositories/pull-stream/sinks/drain.js";

describe("drain sink.abort", () => {
  it("should pass the original error to done when abort is called with an error object", (done) => {
    let storedReadCb: ((end: any, data?: any) => void) | null = null;

    function source(end: any, cb: (end: any, data?: any) => void) {
      if (end) {
        cb(end);
      } else {
        storedReadCb = cb;
      }
    }

    const actualError = new Error("test error");
    let doneCalledWith: any = undefined;

    const sink = drain(null, (err: any) => {
      doneCalledWith = err;
    });

    sink(source);

    // Now call abort with an Error object (not a function)
    // abort(err, cb) where err is an Error
    sink.abort(actualError, () => {
      // After abort completes, check what done was called with
      // The stream ended with actualError, so done should get actualError
      expect(doneCalledWith).toBe(actualError);
      done();
    });
  });
});
```

Hmm, but that doesn't test the function-as-first-arg path. Let me reconsider what changes when `err = false` vs `err = true` in the function-as-first-arg case, focusing on what happens when `sink` is called *after* abort:

```typescript
import drain from "../../../../../../../../../../../subject_repositories/pull-stream/sinks/drain.js";

describe("drain sink.abort", () => {
  it("should invoke done with null when stream ends normally after abort called with only callback", (done) => {
    let sourceEndSignals: any[] = [];

    function source(end: any, cb: (end: any, data?: any) => void) {
      sourceEndSignals.push(end);
      if (end) {
        cb(end);
      }
      // else: async, don't call cb
    }

    const doneCb = jest.fn();
    const sink = drain(null, doneCb);

    // Call abort BEFORE connecting source (read is not set yet)
    const abortCb = jest.fn();
    sink.abort(abortCb);

    // Now connect source - since abort is set, sink should call sink.abort() immediately
    // Original: abort = true -> sink.abort() called -> but read not set... 
    // Actually: if(abort) return sink.abort() - this calls sink.abort() again with no args
    // sink.abort() with no args: err=undefined, not a function, so skip the if
    // abort = undefined || true = true
    // read is now set, so read(true, function(){})
    sink(source);

    // In original: abort=true (set by first abort call), sink(source) sees abort=true, calls sink.abort()
    // sink.abort() -> abort = undefined||true = true -> read(true, ()=>{}) -> source(true, cb) -> cb(true)
    // done is called with null (true===true -> null)

    // In mutated: abort=false (set by first abort call with function), sink(source) sees if(abort)...
    // abort=false is falsy! So if(abort) is FALSE, sink.abort() is NOT called!
    // Instead the while loop runs, source(null, cb) is called, cb is stored (async)
    // done is NOT called

    expect(doneCb).toHaveBeenCalledWith(null);
    done();
  });
});
```

```typescript
import drain from "../../../../../../../../../../../subject_repositories/pull-stream/sinks/drain.js";

describe("drain sink.abort", () => {
  it("should abort stream immediately when sink is connected after abort was called with only a callback", (done) => {
    const endSignals: any[] = [];

    function source(end: any, cb: (end: any, data?: any) => void) {
      endSignals.push(end);
      if (end) {
        cb(end);
      }
      // async when end is falsy
    }

    const doneCb = jest.fn();
    const sink = drain(null, doneCb);

    // Abort before connecting source
    const abortCb = jest.fn();
    sink.abort(abortCb);

    // Connect source after abort
    sink(source);

    // Original: abort=true -> if(abort) triggers -> sink.abort() called -> read(true, fn) -> source(true,cb) -> cb(true) -> done(null)
    // Mutated: abort=false -> if(abort) is falsy -> normal read loop starts -> source(null, cb) -> async, cb not called

    expect(doneCb).toHaveBeenCalledWith(null);
    done();
  });
});
```

Let me trace through more carefully what happens when `sink.abort(callback)` is called before `read` is set.

Looking at `sink.abort`:
```js
sink.abort = function (err, cb) {
  if('function' == typeof err)
    cb = err, err = true  // original: err becomes true
    // mutated: err becomes false
  abort = err || true  // original: true||true=true; mutated: false||true=true
  if(read) return read(abort, cb || function () {})
}
```

So `abort` is ALWAYS `true` in both cases! The difference is only in `err` local variable which isn't used after that.

Wait - `abort = err || true`. In original `err=true`, so `abort = true||true = true`. In mutated `err=false`, so `abort = false||true = true`. Same result!

So the mutation has NO effect on `abort`... unless `err` is passed as something other than a function. Let me re-read the mutation location - it's inside `if('function' == typeof err)` block. After this block, `abort = err || true`. Since `err` is reassigned inside the if-block, the difference is `err=true` vs `err=false`, but `abort = err || true` is always `true`.

This means the mutation only affects the `err` variable which... isn't used elsewhere. Unless there's a case where `abort` is set to something other than `true`... 

Oh wait! What if `err` is passed as a non-function truthy value like an Error object? Then the `if` block is skipped entirely and `abort = err || true = err`. That's unrelated to the mutation.

The mutation seems to have no observable effect based on my analysis. Let me try testing the `err` value passed to `done` when abort is called with a function callback and then the stream ends:

